  // ── HELPER: build amendments[] for a section from CSV data ───────────────────
  function amends(articleNum, sectionNum) {
    return ALL_CHANGES
      .filter(c => c.article_number === articleNum && c.section_number === sectionNum)
      .map(c => ({
        year:         c.year_adopted,
        label:        `Art. ${c.article_number}, §${c.section_number} — ${c.amendment_ref}`,
        status:       c.status,
        effectiveDate: c.effective_date,
        passedDate:   `Source: ${c.pdf_source}`,
        shortSummary: c.change_summary,
        fullText:     c.full_text,
        isNew1971:    c.pdf_source === "1971 edition",
        isNew1973:    c.pdf_source === "1973 edition",
        isNew1975:    c.pdf_source === "1975 edition",
        isNew1977:    c.pdf_source === "1977 edition",
        pdfSource:    c.pdf_source,
      }));
  }
  
